SELECT product_id 
FROM products 
WHERE market_id = (SELECT market_id FROM markets WHERE name = 'Green Meadows Market');

SELECT COUNT(market_id) AS market_count
FROM markets
WHERE county = 'Bell County';

SELECT county, COUNT(market_id) AS number_of_markets
FROM markets
GROUP BY county;

SELECT m.name
FROM markets m
WHERE m.county = 'Middlesboro' AND m.sector = 'Farmers Market';
